static string JsonEscape(string s)
{
    if (s == null) return "null";
    var sb = new StringBuilder();
    sb.Append('"');
    foreach (var c in s)
    {
        switch (c)
        {
            case '\\': sb.Append("\\\\"); break;
            case '"': sb.Append("\\\""); break;
            case '\b': sb.Append("\\b"); break;
            case '\f': sb.Append("\\f"); break;
            case '\n': sb.Append("\\n"); break;
            case '\r': sb.Append("\\r"); break;
            case '\t': sb.Append("\\t"); break;
            default:
                if (c < 0x20)
                {
                    sb.Append("\\u");
                    sb.Append(((int)c).ToString("x4"));
                }
                else sb.Append(c);
                break;
        }
    }
    sb.Append('"');
    return sb.ToString();
}

static class SamlAuthnRequestBuilder
{
    public static XmlDocument BuildAuthnRequest(
        string issuer,
        string destination,
        string assertionConsumerServiceUrl,
        string nameIdFormat,
        bool forceAuthn)
    {
        var doc = new XmlDocument { PreserveWhitespace = true };
        var id = "_" + Guid.NewGuid().ToString("N");
        var issueInstant = DateTime.UtcNow.ToString("o");

        var samlp = "urn:oasis:names:tc:SAML:2.0:protocol";
        var saml = "urn:oasis:names:tc:SAML:2.0:assertion";

        var root = doc.CreateElement("samlp", "AuthnRequest", samlp);
        root.SetAttribute("ID", id);
        root.SetAttribute("Version", "2.0");
        root.SetAttribute("IssueInstant", issueInstant);
        root.SetAttribute("Destination", destination);
        root.SetAttribute("AssertionConsumerServiceURL", assertionConsumerServiceUrl);
        if (forceAuthn) root.SetAttribute("ForceAuthn", "true");

        root.SetAttribute("xmlns:samlp", samlp);
        root.SetAttribute("xmlns:saml", saml);

        var issuerEl = doc.CreateElement("saml", "Issuer", saml);
        issuerEl.InnerText = issuer;
        root.AppendChild(issuerEl);

        var nameIdPolicy = doc.CreateElement("samlp", "NameIDPolicy", samlp);
        nameIdPolicy.SetAttribute("Format", nameIdFormat);
        nameIdPolicy.SetAttribute("AllowCreate", "true");
        root.AppendChild(nameIdPolicy);

        var requestedAuthnContext = doc.CreateElement("samlp", "RequestedAuthnContext", samlp);
        requestedAuthnContext.SetAttribute("Comparison", "exact");
        var classRef = doc.CreateElement("saml", "AuthnContextClassRef", saml);
        classRef.InnerText = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport";
        requestedAuthnContext.AppendChild(classRef);
        root.AppendChild(requestedAuthnContext);

        doc.AppendChild(root);
        return doc;
    }
}

static class SamlAuthnRequestSigner
{
    public static void SignXml(XmlDocument doc, X509Certificate2 signingCert)
    {
        if (doc == null) throw new ArgumentNullException(nameof(doc));
        if (signingCert == null) throw new ArgumentNullException(nameof(signingCert));

        var rsa = signingCert.GetRSAPrivateKey();
        if (rsa == null) throw new InvalidOperationException("Certificate does not have an RSA private key.");

        var signedXml = new SignedXml(doc)
        {
            SigningKey = rsa
        };

        signedXml.SignedInfo.CanonicalizationMethod = SignedXml.XmlDsigExcC14NTransformUrl;
        signedXml.SignedInfo.SignatureMethod = SignedXml.XmlDsigRSASHA1Url;

        var reference = new Reference();
        var id = doc.DocumentElement?.GetAttribute("ID");
        if (string.IsNullOrWhiteSpace(id)) throw new InvalidOperationException("AuthnRequest missing ID attribute.");

        reference.Uri = "#" + id;
        reference.DigestMethod = SignedXml.XmlDsigSHA1Url;

        reference.AddTransform(new XmlDsigEnvelopedSignatureTransform());
        reference.AddTransform(new XmlDsigExcC14NTransform());

        signedXml.AddReference(reference);

        var keyInfo = new KeyInfo();
        var x509Data = new KeyInfoX509Data(signingCert);
        x509Data.AddIssuerSerial(signingCert.Issuer, signingCert.SerialNumber);
        keyInfo.AddClause(x509Data);
        signedXml.KeyInfo = keyInfo;

        signedXml.ComputeSignature();
        var signature = signedXml.GetXml();

        var root = doc.DocumentElement!;
        var issuerNode = root.SelectSingleNode("//*[local-name()='Issuer' and namespace-uri()='urn:oasis:names:tc:SAML:2.0:assertion']");
        if (issuerNode != null && issuerNode.ParentNode == root)
        {
            root.InsertAfter(signature, issuerNode);
        }
        else
        {
            root.PrependChild(signature);
        }
    }
}

