static class SamlHttpRedirectBinding
{
    public static string EncodeRequest(string samlRequestXml)
    {
        var bytes = Encoding.UTF8.GetBytes(samlRequestXml);
        using var output = new MemoryStream();
        using (var deflate = new DeflateStream(output, CompressionLevel.Optimal, leaveOpen: true))
